settings.custom_css:
.shiprocket-tracking-wrapper {
  /* Increased top padding significantly; kept bottom at 4px */
  padding: 50px 15px 4px !important; 
  background-color: transparent;
  display: flex;
  justify-content: center;
  width: 100%;
}

.tracking-card {
  background: #ffffff;
  width: 100%;
  max-width: 750px; 
  padding: 40px 20px 50px; 
  border-radius: 16px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.06);
  text-align: center;
  border: 1px solid #eef9ff;
  box-sizing: border-box;
}

/* Rest of your existing styles below */
.track-heading-large {
  color: #0e436b;
  font-size: 32px; 
  margin-bottom: 35px;
  font-weight: 700;
  margin-top: 0;
  letter-spacing: -0.5px;
}

.search-options {
  display: flex;
  justify-content: center;
  gap: 30px; 
  margin-bottom: 25px;
  flex-wrap: wrap;
  align-items: center;
}

.search-by-text {
  font-weight: 600;
  color: #0e436b;
  font-size: 16px;
}

.radio-item {
  display: flex;
  align-items: center;
  cursor: pointer;
  font-size: 16px;
  color: #0e436b;
}

.radio-item input {
  margin-right: 8px;
  accent-color: #0e436b;
  width: 18px;
  height: 18px;
}

.input-row {
  max-width: 500px; 
  margin: 0 auto;
}

.input-row input {
  width: 100%;
  padding: 14px;
  border: 1px solid #0e436b;
  border-radius: 4px;
  background-color: #eef9ff;
  box-sizing: border-box;
  font-size: 14px;
  color: #000000 !important;
}

.input-row input::placeholder {
  color: #000000 !important;
  opacity: 0.7;
}

.btn-submit {
  background-color: #0e436b;
  color: #ffffff !important;
  border: none;
  padding: 16px;
  width: 100%;
  max-width: 500px;
  border-radius: 6px;
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  margin-top: 20px;
  transition: opacity 0.2s;
}

.btn-submit:hover { opacity: 0.9; }

.error-text {
  color: #d93025;
  font-size: 13px;
  margin-top: 8px;
  text-align: center;
  font-weight: 600;
}

@media screen and (max-width: 768px) {
  .shiprocket-tracking-wrapper { padding-top: 80px !important; }
  .tracking-card { padding: 30px 15px 40px; }
  .track-heading-large { font-size: 24px; margin-bottom: 25px; }
}

settings.custom_javascript:
window.updatePlaceholder = function(val) {
  const input = document.getElementById('track_id_input_final');
  const error = document.getElementById('error-message-final');

  if (input) {
    // 1. Update the placeholder based on selection
    input.placeholder = (val === 'order_id') ? "Enter Order ID to search" : "Enter AWB number to search";

    // 2. Refresh the text (Clear the input)
    input.value = ""; 
  }

  // 3. Hide any previous error messages
  if (error) {
    error.style.display = 'none';
  }
};

window.launchShiprocket = function() {
  const input = document.getElementById('track_id_input_final');
  const error = document.getElementById('error-message-final');
  const typeSelection = document.querySelector('input[name="track_type_final"]:checked');

  if (!input || !typeSelection) return;

  // Clean the input: remove '#' and whitespace
  const trackId = input.value.trim().replace(/#/g, '');
  const searchType = typeSelection.value;

  if (!trackId) {
    error.textContent = "Please enter tracking details.";
    error.style.display = 'block';
    return;
  }

  error.style.display = 'none';

  let finalUrl = "";

  if (searchType === 'order_id') {
    finalUrl = "https://bubbleme.shiprocket.co/tracking/order/" + trackId;
  } else {
    // AWB Logic: Handle Blue Dart (Starts with 77)
    if (trackId.startsWith('77')) {
      const baseUrl = "https://www.bluedart.com/web/guest/trackdartresultthirdparty";
      const params = new URLSearchParams();
      params.append('trackFor', '0');
      params.append('trackNo', trackId);
      finalUrl = baseUrl + "?" + params.toString();
    } else {
      finalUrl = "https://shiprocket.co/tracking/" + trackId;
    }
  }

  window.location.href = finalUrl;
};

